const TEMPLATES = [
  {
    name: 'Custom Backtest',
    desc: 'Run a custom strategy backtest using the Aura Alpha engine with your own parameters.',
  },
  {
    name: 'Factor Analysis',
    desc: 'Analyze factor exposures across your portfolio using Polars/DuckDB.',
  },
  {
    name: 'Signal Research',
    desc: 'Explore new signal ideas with live OHLCV data and indicator libraries.',
  },
  {
    name: 'Risk Decomposition',
    desc: 'Decompose portfolio risk by sector, region, and factor loading.',
  },
  {
    name: 'ML Feature Engineering',
    desc: 'Build and test ML features for strategy models using scikit-learn/PyTorch.',
  },
  {
    name: 'Data Explorer',
    desc: 'Browse OHLCV cache, signals, and backtest results interactively.',
  },
];

export default function JupyterConnect() {
  const [serverUrl, setServerUrl] = useState('http://localhost:8888');
  const [token, setToken] = useState('');
  const [connected, setConnected] = useState(false);
  const [notebooks, setNotebooks] = useState([]);

  const handleConnect = () => {
    setConnected(true);
    setNotebooks([
      { name: 'backtest_analysis.ipynb', modified: '2 hours ago', cells: 24 },
      { name: 'signal_research.ipynb', modified: '1 day ago', cells: 18 },
      { name: 'risk_decomposition.ipynb', modified: '3 days ago', cells: 31 },
    ]);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div>
          <div style={styles.title}>Jupyter Connect</div>
          <div style={styles.subtitle}>
            Connect to Jupyter for custom analysis, backtesting, and ML research
          </div>
        </div>
        <div
          style={{
            ...styles.statusBadge,
            background: connected ? '#22C55E15' : '#F5914920',
            color: connected ? '#22C55E' : '#F59149',
            border: `1px solid ${connected ? '#22C55E30' : '#F5914930'}`,
          }}
        >
          <span style={{
            width: 6, height: 6, borderRadius: '50%',
            background: connected ? '#22C55E' : '#F59149',
          }} />
          {connected ? 'Connected' : 'Disconnected'}
        </div>
      </div>

      <div style={styles.connectBar}>
        <input
          style={styles.input}
          placeholder="Jupyter server URL"
          value={serverUrl}
          onChange={e => setServerUrl(e.target.value)}
        />
        <input
          style={{ ...styles.input, maxWidth: 200 }}
          placeholder="Token (optional)"
          type="password"
          value={token}
          onChange={e => setToken(e.target.value)}
        />
        <button style={styles.connectBtn} onClick={handleConnect}>
          {connected ? 'Reconnect' : 'Connect'}
        </button>
      </div>

      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12 }}>Notebook Templates</div>
      <div style={styles.grid}>
        {TEMPLATES.map(t => (
          <div key={t.name} style={{ ...styles.card, cursor: 'pointer' }}>
            <div style={styles.cardTitle}>{t.name}</div>
            <div style={styles.cardDesc}>{t.desc}</div>
          </div>
        ))}
      </div>

      {connected && notebooks.length > 0 && (
        <>
          <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, marginTop: 8 }}>
            Active Notebooks
          </div>
          {notebooks.map(nb => (
            <div key={nb.name} style={{ ...styles.card, marginBottom: 12, cursor: 'pointer' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <div style={{ ...styles.cardTitle, fontFamily: "'JetBrains Mono', monospace" }}>
                    {nb.name}
                  </div>
                  <div style={styles.cardDesc}>
                    {nb.cells} cells -- modified {nb.modified}
                  </div>
                </div>
                <button
                  style={{
                    ...styles.connectBtn,
                    padding: '6px 14px',
                    fontSize: 13,
                    background: '#22C55E',
                  }}
                >
                  Open
                </button>
              </div>
            </div>
          ))}
        </>
      )}

      {!connected && (
        <>
          <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, marginTop: 8 }}>
            Preview: Backtest Cell Output
          </div>
          <div style={styles.cellBlock}>
            <div style={styles.cellLabel}>In [1]</div>
            {`from data.athena_backtest_v3 import run_backtest\nresults = run_backtest(strategy="Breakout", region="us", start="2024-01-01")\nprint(f"Sharpe: {results.sharpe:.2f}, PF: {results.profit_factor:.2f}")`}
          </div>
          <div style={styles.cellBlock}>
            <div style={{ ...styles.cellLabel, color: '#22C55E' }}>Out [1]</div>
            {`Sharpe: 1.47, PF: 2.31`}
          </div>
        </>
      )}
    </div>
  );
}
